const raw = $input.first().json;
const content = raw.choices && raw.choices[0] && raw.choices[0].message && raw.choices[0].message.content;
if (!content) throw new Error('Réponse OpenAI vide: ' + JSON.stringify(raw).slice(0, 500));
let s = String(content).trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/,'').trim();
let parsed;
try {
  parsed = JSON.parse(s);
} catch (e) {
  throw new Error('JSON invalide: ' + e.message + ' — ' + s.slice(0, 300));
}
const meta = $('9 - Assemble LLM payload').first().json;
const rawName = parsed.candidate_name ?? parsed.candidateName ?? parsed.full_name ?? parsed.nom_candidat ?? parsed.nomComplet;
function isNoiseCandName(n) {
  if (n == null || String(n).trim() === '') return true;
  const x = String(n).normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().trim();
  if (/^(a propos de moi|about me|soft skills|hard skills|formation|projets?|competences|skills|resume|summary)$/.test(x)) return true;
  if (/\bpropos\b/.test(x) && /\bmoi\b/.test(x)) return true;
  if (/\babout\b/.test(x) && /\bme\b/.test(x)) return true;
  return false;
}
const candidateRaw = rawName != null && String(rawName).trim() !== '' ? String(rawName).trim() : null;
const candidate_name = candidateRaw && !isNoiseCandName(candidateRaw) ? candidateRaw : null;
function nsp(v) { return String(v || '').replace(/\s+/g, ' ').trim(); }
function isNoiseEmployerName(v) {
  const t = nsp(v).toLowerCase();
  if (!t) return true;
  if (/^(e[- ]?commerce|shopping|portfolio|project|projet|application|app|website|site web|data analyst|bi|power bi|cloud engineer|azure\/aws)$/.test(t)) return true;
  if (/\b(project|projet|website|application|portfolio|capstone)\b/.test(t)) return true;
  return false;
}
function lastEmployerFromCv(cv) {
  const txt = String(cv || '');
  const re = /(?:Stagiaire|Stage|Développeur|Developer|Engineer|Ingénieur|Intern|Freelance)[^\n–-]{0,90}[–-]\s*([^\n,]+)/gi;
  const arr = [];
  let m;
  while ((m = re.exec(txt)) !== null) {
    const company = nsp(m[1]);
    if (isNoiseEmployerName(company)) continue;
    const win = txt.slice(Math.max(0,m.index-120), Math.min(txt.length,m.index+360));
    const years = [...win.matchAll(/\b(19|20)\d{2}\b/g)].map(mm=>parseInt(mm[0],10));
    const maxYear = years.length ? Math.max(...years) : -1;
    arr.push({ company, maxYear, pos: m.index });
  }
  if (!arr.length) return null;
  arr.sort((a,b)=> (b.maxYear-a.maxYear) || (a.pos-b.pos));
  return arr[0].company;
}
const cvText = String($('8 - Get CV text (PCA, no OpenAI)').first().json.text || '');
const expCount = Number.isFinite(Number(parsed.experience_count)) ? Math.max(0, parseInt(String(parsed.experience_count),10)) : 0;
let score = Number.isFinite(Number(parsed.score)) ? Number(parsed.score) : 50;
score = Math.max(0, Math.min(100, score));
if (expCount === 0 && score > 68) score = 68;
let decision = String(parsed.decision || '').toUpperCase().trim();
if (expCount === 0 && decision === 'ACCEPTEE' && score <= 70) decision = 'A REVOIR';
if (!['ACCEPTEE','REFUSEE','A REVOIR','NON_LISIBLE'].includes(decision)) decision = 'A REVOIR';
const fromCv = lastEmployerFromCv(cvText);
const llmLeRaw = parsed.last_employer != null ? nsp(parsed.last_employer) : '';
const llmLe = isNoiseEmployerName(llmLeRaw) ? '' : llmLeRaw;
const last_employer = expCount === 0 ? null : (fromCv || llmLe || null);
if (expCount === 0) {
  parsed.experience_duration = '';
  parsed.experience_years_avg = null;
}
let oc = String(parsed.offer_context || '');
oc = oc.replace(/\bscore\s*(de|à|:)\s*\d{1,3}\b/gi, `score de ${score}`);
oc = oc.replace(/\bnote\s*(de|à|:)\s*\d{1,3}\b/gi, `note de ${score}`);
parsed.offer_context = oc;
return [{ json: { ...parsed, score, decision, candidatureId: meta.candidatureId, offerTitle: meta.offerTitle, offerDescription: meta.offerDescription, candidate_name, last_employer } }];

const cvRes = $input.first().json;
const offer = $('7 - Set Offer Context').first().json;
const init = $('1 - Initialize Candidate API').first().json;
const email = $('2 - Merge (Email + API response)').first().json;

let attachmentFileName = '';
try {
  const mbin = $('2 - Merge (Email + API response)').first().binary || {};
  const bk = Object.keys(mbin).find((x) => /^attachment_/i.test(x));
  if (bk && mbin[bk] && mbin[bk].fileName) attachmentFileName = String(mbin[bk].fileName);
} catch (e) {}

let cvText = String(cvRes.text || '').trim();
const cvApiTooShort = cvRes.tooShort === true || cvText.length < 20;
if (!cvText || cvText.length < 20) {
  cvText = '[EXTRACTION CV INSUFFISANTE — dossier partiel côté texte]\nPeu de caractères extraits (PDF image/scanné si le serveur n a pas OPENAI_API_KEY pour lecture PDF avancée).\nNe pas prendre le nom « De: » comme candidate_name si le nom du fichier joint ou le contenu du CV indiquent un autre candidat ; sinon laisser candidate_name vide.';
}
const offerTitle = String(offer.offerTitle || '');
const offerDescription = String(offer.offerDescription || '');
const subject = String(email.subject || '');
const fromVal = email.from && email.from.value && email.from.value[0];
const fromLine = fromVal ? `${fromVal.name || ''} <${fromVal.address}>`.trim() : String(email.from || '');
const bodySnippet = String(email.text || email.textPlain || '').slice(0, 2500);

const internalMatch = typeof offer._offerMatchScore === 'number' && Number.isFinite(offer._offerMatchScore) ? offer._offerMatchScore : null;
const CATALOG_MIN = 18;
const offerFromCatalog = internalMatch != null && internalMatch >= CATALOG_MIN;
const matchLine = internalMatch != null ? ('\n[Métadonnée PCA — matching sujet → catalogue] Score interne n8n : ' + internalMatch + ' (seuil dans ce workflow : ' + CATALOG_MIN + '). ' + (offerFromCatalog ? 'Offre catalogue retenue : le score mesure surtout l adéquation CV ↔ OFFRE CIBLE (titre + contexte), sans contredire fortement le SUJET (OBJET).' : 'Pas de match catalogue ferme : le titre OFFRE CIBLE suit le SUJET — le score mesure surtout l adéquation CV ↔ OBJET ; OFFRE CIBLE rappelle le même intitulé.')) : '';

const llmUserMessage = `CONTEXTE EMAIL (message reçu):\nRéférence A — SUJET (OBJET du mail, intention candidat) : ${subject}\nDe: ${fromLine}\nNom API: ${init.candidateName || init.fullName || ''}\nEmail API: ${init.email || ''}\nExtrait corps:\n${bodySnippet}\n\nRéférence B — OFFRE CIBLE (titre + contexte : ligne catalogue PCA si matching sujet→catalogue OK, sinon alignée sur le sujet) :\nTitre: ${offerTitle}\nContexte: ${offerDescription}${matchLine}\n\nMétadonnées extraction PCA : tooShort API = ${cvApiTooShort} ; pièce jointe CV (nom fichier) = ${attachmentFileName || 'N/A'}.\nRègle identité : candidate_name = en-tête du TEXTE CV uniquement. Si l expéditeur du mail et le fichier CV portent des patronymes différents, ne pas inventer : prioriser le TEXTE CV ; sinon laisser candidate_name vide.\n\nTEXTE CV (décodé serveur PCA, tronqué) :\n${cvText.slice(0, 14000)}\n\nRÈGLE DE NOTATION — score (0-100) et décision : croiser A (OBJET) et B (OFFRE CIBLE) avec le CV. Si métadonnée PCA indique offre catalogue retenue : scorer surtout CV↔B, pénaliser hors-métier vs B ou contradiction forte avec A. Sinon : scorer surtout CV↔A ; B est le rappel du titre. Toujours pénaliser décalage stack/métier évident. Pas de score « bon CV en général » sans lien A/B.\n\nRÈGLE last_employer : entreprise réelle de l expérience la plus récente. Interdit de renvoyer un titre de projet ou d offre comme employeur.\n\nCas CV court ou partiellement lisible : continuer l analyse normalement, éviter NON_LISIBLE par défaut si des informations exploitables existent (nom/skills/expérience/sujet/offre).\nAnalyse ce dossier et renvoie uniquement le JSON demandé.`;

const systemPrompt = `Tu es un expert RH PCA. Tu fusionnes l email de candidature et le texte du CV.\nRéponds UNIQUEMENT avec un objet JSON valide (sans markdown), avec exactement ces clés :\nsummary, skills, experience, strengths, risks, score (0-100), decision (une parmi ACCEPTEE, REFUSEE, A REVOIR, NON_LISIBLE), offer_context, school, school_type (PUBLIC, PRIVE ou null), phone, experience_count, experience_duration, experience_years_avg, last_employer, candidate_name\nContraintes de format :\n- candidate_name : prénom+nom extraits de l en-tête CV uniquement (souvent en haut, parfois en majuscules). Interdit : titre de section (À propos de moi, Formation, Projets, Compétences...), nom email expéditeur, champ Nom API, nom de fichier.\n- skills : string uniquement, compétences séparées par virgules (pas de tableau JSON).\n- experience : string uniquement, lisible RH (pas de JSON imbriqué).\n- offer_context : 2 à 4 phrases en français ; mentionner SUJET, OFFRE CIBLE et logique de scoring (catalogue vs sujet). Toute mention de score dans ce texte doit reprendre exactement le même nombre que la clé JSON score (interdit d écrire un autre chiffre).\n- summary, strengths, risks : prose française basée sur preuves.\n- experience_count : compter UNIQUEMENT emplois/stages en entreprise ; exclure projets académiques/perso.\n- experience_duration : cohérente avec experience_count ; vide si experience_count = 0.\n- experience_years_avg : moyenne annuelle ; null si experience_count = 0.\n- last_employer : organisme réel le plus récent ; jamais un titre de projet/offre. Si experience_count = 0, chaîne vide.\n- score : nombre 0-100 strictement basé sur adéquation CV↔offre/sujet ; si experience_count = 0, éviter score élevé (>68) sauf preuves exceptionnelles explicites.\n- decision : cohérente avec score. Si experience_count = 0 et score <= 70, préférer A REVOIR plutôt que ACCEPTEE.\n- NON_LISIBLE : utiliser seulement si données insuffisantes même après exploitation email + fragments CV ; ne pas l appliquer automatiquement pour CV court.`;

return [
  {
    json: {
      llmUserMessage,
      systemPrompt,
      candidatureId: init.id,
      offerTitle,
      offerDescription,
    },
  },
];

const data = $input.first().json;
const offers = Array.isArray(data.offers) ? data.offers : [];
const merge = $('2 - Merge (Email + API response)').first().json;
const subjectRaw = String(merge.subject || '').trim();

function norm(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/^re:\s*|^fwd:\s*/gi, '')
    .replace(/[\u2010-\u2015\u2212]/g, '-')
    .replace(/[_\u2013\u2014\-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const STOP = new Set(['le', 'la', 'les', 'des', 'une', 'pour', 'avec', 'stage', 'pfe', 'offre', 'emploi', 'candidature', 'poste', 'job', 'd', 'de', 'du', 'et', 'ou', 'the', 'a', 'an']);

function tokens(s) {
  return norm(s).split(/[^a-z0-9\u00c0-\u024f]+/).filter((t) => t.length > 1 && !STOP.has(t));
}

const subjN = norm(subjectRaw);
const subjTokens = new Set(tokens(subjectRaw));

const GROUPS = [
  { keys: ['devops', 'docker', 'aws', 'kubernetes', 'argo', 'terraform', 'jenkins', 'gitlab'], weight: 58 },
  { keys: ['data', 'analyst', 'bi', 'power', 'etl'], weight: 52 },
  { keys: ['full', 'stack', 'react', 'javascript', 'angular', 'vue'], weight: 48 },
  { keys: ['java', 'spring', 'boot'], weight: 42 },
  { keys: ['cloud', 'azure'], weight: 36 },
];

function scoreOffer(offer) {
  const title = String(offer.title || '');
  const tN = norm(title);
  let score = 0;
  for (const g of GROUPS) {
    const subHit = g.keys.some((k) => subjN.includes(k));
    const titHit = g.keys.some((k) => tN.includes(k));
    if (subHit && titHit) score += g.weight;
    if (subHit && !titHit) score -= 24;
  }
  if (subjN && tN && tN.length > 24 && subjN.length > 24 && (subjN.includes(tN) || tN.includes(subjN))) score += 88;
  let overlap = 0;
  for (const t of tokens(title)) {
    if (subjTokens.has(t)) overlap++;
  }
  score += overlap * 8;
  return score;
}

let best = null;
let bestScore = -1e9;
for (const o of offers) {
  const sc = scoreOffer(o);
  if (sc > bestScore) {
    bestScore = sc;
    best = o;
  }
}

const MIN_SCORE = 18;
let offerTitle;
let offerDescription;

if (best && bestScore >= MIN_SCORE) {
  offerTitle = best.title;
  offerDescription = [best.company, best.location].filter(Boolean).join(' - ');
} else {
  offerTitle = subjectRaw.replace(/^re:\s*|^fwd:\s*/gi, '').trim() || 'Poste';
  offerDescription = '';
}

return [{ json: { offerTitle, offerDescription, subject: subjectRaw, _offerMatchScore: bestScore } }];

const items = $input.all();
const baseUrl = 'http://127.0.0.1:9000';

return items.map((item) => {
  const uploadUrl = String(item.json.uploadUrl || '').trim();
  let fullUploadUrl = baseUrl + (uploadUrl.startsWith('/') ? uploadUrl : '/' + uploadUrl);
  if (!fullUploadUrl.startsWith('http')) fullUploadUrl = baseUrl + '/' + (uploadUrl.replace(/^\//, '') || 'cvs');
  const bin = item.binary || {};
  const attKey = Object.keys(bin).find((k) => k.startsWith('attachment_'));
  if (attKey && attKey !== 'attachment_0') bin.attachment_0 = bin[attKey];
  return { json: { ...item.json, fullUploadUrl }, binary: bin };
});

// Ne garder que les emails qui ressemblent à une candidature (sujet ou pièce jointe CV)
const items = $input.all();
const subjectKeywords = /candidature|cv|application|postule|resume|curriculum|offre|emploi|stage|pfe|stagiaire|internship|développeur|developpeur|developer|full[\s-]*stack|ingenieur|ingénieur/i;

const filtered = items.filter((item) => {
  const subject = String(item.json.subject || '').toLowerCase();
  const bin = item.binary || {};
  const attKeys = Object.keys(bin).filter((k) => /^attachment_?\d*$/i.test(k) || k === 'data');
  let hasCvAttachment = false;
  for (const k of attKeys) {
    const b = bin[k];
    if (!b) continue;
    const fn = String(b.fileName || '');
    const mime = String(b.mimeType || b.mime || '');
    if (/\.(pdf|docx?)$/i.test(fn) || /pdf|msword|wordprocessingml|officedocument/i.test(mime)) {
      hasCvAttachment = true;
      break;
    }
  }
  return subjectKeywords.test(subject) || hasCvAttachment;
});

return filtered;

